import os, shutil
from pathlib import Path

def deleteFile(user,file):
  path = 'users/' + user + '/files/'
  if os.path.isfile((Path(path).resolve() / file)):
    shutil.rmtree("users/" + user + "/files/" + file)
  else: 
    print('File not found!')